window.UE = (function() {
    var instances = {};
    
    function createToolbar(container, tools, options) {
        var toolbar = document.createElement('div');
        toolbar.className = 'ueditor-toolbar';
        toolbar.style.cssText = 'border-bottom:1px solid #e5e7eb;background:#f9fafb;padding:4px 8px;display:flex;flex-wrap:wrap;gap:2px;';
        
        var toolButtons = {
            'bold': {icon: 'B', title: '加粗'},
            'italic': {icon: 'I', title: '斜体'},
            'underline': {icon: 'U', title: '下划线'},
            'strikethrough': {icon: 'S', title: '删除线'},
            'undo': {icon: '↩', title: '撤销'},
            'redo': {icon: '↪', title: '重做'},
            'justifyleft': {icon: '←', title: '左对齐'},
            'justifycenter': {icon: '⊼', title: '居中'},
            'justifyright': {icon: '→', title: '右对齐'},
            'justifyjustify': {icon: '⇔', title: '两端对齐'},
            'insertorderedlist': {icon: '1.', title: '有序列表'},
            'insertunorderedlist': {icon: '•', title: '无序列表'},
            'link': {icon: '🔗', title: '链接'},
            'unlink': {icon: '✕', title: '取消链接'},
            'insertimage': {icon: '🖼', title: '插入图片'},
            'forecolor': {icon: 'A', title: '字体颜色'},
            'backcolor': {icon: '🖍', title: '背景颜色'},
            'fontsize': {icon: '12px', title: '字号'},
            'selectall': {icon: '☑', title: '全选'},
            'cleardoc': {icon: '🗑', title: '清空'},
            'preview': {icon: '👁', title: '预览'},
            'source': {icon: '&lt;/&gt;', title: '源代码'},
            'fullscreen': {icon: '⛶', title: '全屏'}
        };
        
        for (var i = 0; i < tools.length; i++) {
            var tool = tools[i];
            if (tool === '|') {
                var divider = document.createElement('span');
                divider.style.cssText = 'display:inline-block;width:1px;height:20px;background:#d1d5db;margin:0 4px;';
                toolbar.appendChild(divider);
            } else if (toolButtons[tool]) {
                var btn = document.createElement('button');
                btn.innerHTML = toolButtons[tool].icon;
                btn.title = toolButtons[tool].title;
                btn.style.cssText = 'padding:4px 8px;border:1px solid #d1d5db;border-radius:3px;background:#fff;color:#374151;font-size:12px;cursor:pointer;transition:all .2s;min-width:28px;height:28px;display:flex;align-items:center;justify-content:center;';
                btn.onclick = function(t) { return function() { execCommand(t); }; }(tool);
                btn.onmouseenter = function() { this.style.borderColor = '#3b82f6'; this.style.background = '#eff6ff'; };
                btn.onmouseleave = function() { this.style.borderColor = '#d1d5db'; this.style.background = '#fff'; };
                toolbar.appendChild(btn);
            }
        }
        
        return toolbar;
    }
    
    function createEditor(container, options) {
        var editorContainer = document.createElement('div');
        editorContainer.className = 'ueditor-container';
        editorContainer.style.cssText = 'border:1px solid #e5e7eb;border-radius:4px;overflow:hidden;background:#fff;';
        
        var toolbar = createToolbar(editorContainer, options.toolbars[0], options);
        editorContainer.appendChild(toolbar);
        
        var editArea = document.createElement('div');
        editArea.className = 'ueditor-edit-area';
        editArea.style.cssText = 'width:100%;height:' + (options.initialFrameHeight - 36) + 'px;border:none;overflow-y:auto;';
        
        var editBody = document.createElement('div');
        editBody.className = 'ueditor-body';
        editBody.setAttribute('contenteditable', 'true');
        editBody.style.cssText = 'margin:0;padding:15px;background:#fff;min-height:' + (options.initialFrameHeight - 66) + 'px;outline:none;word-break:break-word;overflow-wrap:break-word;';
        
        editArea.appendChild(editBody);
        editorContainer.appendChild(editArea);
        
        container.parentNode.replaceChild(editorContainer, container);
        
        var instance = {
            container: editorContainer,
            toolbar: toolbar,
            editArea: editArea,
            editBody: editBody,
            options: options,
            events: {},
            body: editBody,
            document: document,
            ready: true,
            pendingQueue: []
        };
        
        editBody.oninput = function() {
            if (instance.events['contentChange']) {
                instance.events['contentChange'].forEach(function(fn) { fn(); });
            }
        };
        
        editBody.onpaste = function(e) {
            var clipboardData = e.clipboardData || window.clipboardData;
            if (clipboardData) {
                var html = clipboardData.getData('text/html');
                if (html) {
                    e.preventDefault();
                    document.execCommand('insertHTML', false, html);
                }
            }
        };
        
        if (instance.pendingQueue.length > 0) {
            while (instance.pendingQueue.length > 0) {
                var task = instance.pendingQueue.shift();
                if (task.action === 'setContent') {
                    instance.body.innerHTML = task.value;
                } else if (task.action === 'getContent') {
                    task.callback(instance.body.innerHTML);
                }
            }
        }
        
        setTimeout(function() {
            if (instance.events['ready']) {
                instance.events['ready'].forEach(function(fn) { fn(); });
            }
        }, 0);
        
        instances[options.id] = instance;
        return instance;
    }
    
    function execCommand(cmd) {
        var instance = window.UEDITOR_INSTANCE;
        if (!instance || !instance.document) return;
        
        var doc = instance.document;
        var selection = window.getSelection();
        
        if (selection.rangeCount === 0) {
            selection = instance.editBody.ownerDocument.defaultView.getSelection();
        }
        
        switch(cmd) {
            case 'bold': doc.execCommand('bold', false, null); break;
            case 'italic': doc.execCommand('italic', false, null); break;
            case 'underline': doc.execCommand('underline', false, null); break;
            case 'strikethrough': doc.execCommand('strikeThrough', false, null); break;
            case 'undo': doc.execCommand('undo', false, null); break;
            case 'redo': doc.execCommand('redo', false, null); break;
            case 'justifyleft': doc.execCommand('justifyLeft', false, null); break;
            case 'justifycenter': doc.execCommand('justifyCenter', false, null); break;
            case 'justifyright': doc.execCommand('justifyRight', false, null); break;
            case 'justifyjustify': doc.execCommand('justifyFull', false, null); break;
            case 'insertorderedlist': doc.execCommand('insertOrderedList', false, null); break;
            case 'insertunorderedlist': doc.execCommand('insertUnorderedList', false, null); break;
            case 'outdent': doc.execCommand('outdent', false, null); break;
            case 'indent': doc.execCommand('indent', false, null); break;
            case 'selectall': 
                var range = doc.createRange();
                range.selectNodeContents(instance.body);
                selection.removeAllRanges();
                selection.addRange(range);
                break;
            case 'cleardoc': instance.body.innerHTML = ''; break;
            case 'link': 
                var url = prompt('请输入链接地址：', 'http://');
                if (url) doc.execCommand('createLink', false, url);
                break;
            case 'unlink': doc.execCommand('unlink', false, null); break;
            case 'insertimage': 
                var url = prompt('请输入图片URL：', '');
                if (url) {
                    var img = document.createElement('img');
                    img.src = url;
                    img.style.cssText = 'max-width:100%;height:auto;display:block;margin:10px auto;border-radius:4px;';
                    doc.execCommand('insertHTML', false, img.outerHTML);
                }
                break;
            case 'forecolor': 
                var color = prompt('请输入颜色值（如 #ff0000）：', '#000000');
                if (color) doc.execCommand('foreColor', false, color);
                break;
            case 'backcolor': 
                var color = prompt('请输入背景颜色值（如 #ffff00）：', '#ffffff');
                if (color) doc.execCommand('hiliteColor', false, color);
                break;
            case 'fontsize': 
                var size = prompt('请输入字体大小（如 16px）：', '14px');
                if (size) doc.execCommand('fontSize', false, size);
                break;
            case 'preview': 
                var win = window.open('', '_blank');
                win.document.write('<html><head><title>预览</title><style>body{font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,Helvetica Neue,Arial,sans-serif;font-size:14px;line-height:1.8;color:#333;padding:20px;max-width:800px;margin:0 auto;}img{max-width:100%;height:auto;}</style></head><body>' + instance.body.innerHTML + '</body></html>');
                win.document.close();
                break;
            case 'source':
                var textarea = instance.container.querySelector('.ueditor-source');
                if (textarea) {
                    instance.body.innerHTML = textarea.value;
                    textarea.remove();
                    instance.editArea.style.display = 'block';
                } else {
                    textarea = document.createElement('textarea');
                    textarea.className = 'ueditor-source';
                    textarea.style.cssText = 'width:100%;height:' + (instance.options.initialFrameHeight - 36) + 'px;border:none;resize:none;font-family:monospace;font-size:12px;background:#1e293b;color:#e2e8f0;padding:10px;';
                    textarea.value = instance.body.innerHTML;
                    instance.container.appendChild(textarea);
                    instance.editArea.style.display = 'none';
                }
                break;
            case 'fullscreen':
                if (instance.container.style.position === 'fixed') {
                    instance.container.style.position = 'relative';
                    instance.container.style.top = 'auto';
                    instance.container.style.left = 'auto';
                    instance.container.style.width = '100%';
                    instance.container.style.height = instance.options.initialFrameHeight + 'px';
                    instance.container.style.zIndex = 'auto';
                    instance.editArea.style.height = (instance.options.initialFrameHeight - 36) + 'px';
                } else {
                    instance.container.style.position = 'fixed';
                    instance.container.style.top = '0';
                    instance.container.style.left = '0';
                    instance.container.style.width = '100%';
                    instance.container.style.height = '100%';
                    instance.container.style.zIndex = '9999';
                    instance.editArea.style.height = 'calc(100% - 36px)';
                }
                break;
        }
    }
    
    return {
        getEditor: function(id, options) {
            var defaultOptions = {
                id: id,
                toolbars: [['bold','italic','underline','strikethrough','|','undo','redo','|','justifyleft','justifycenter','justifyright','justifyjustify','|','insertorderedlist','insertunorderedlist','|','link','unlink','|','insertimage','|','forecolor','backcolor','|','preview','source','fullscreen']],
                initialFrameHeight: 450,
                initialFrameWidth: '100%',
                autoHeightEnabled: false,
                enableAutoSave: false
            };
            
            options = Object.assign(defaultOptions, options);
            
            var container = document.getElementById(id);
            if (!container) {
                console.error('UEditor container not found: ' + id);
                return null;
            }
            
            window.UEDITOR_INSTANCE = createEditor(container, options);
            
            return {
                getContent: function(callback) {
                    var instance = window.UEDITOR_INSTANCE;
                    if (!instance) {
                        console.error('UEditor instance not found');
                        return '';
                    }
                    if (instance.ready && instance.body) {
                        var content = instance.body.innerHTML;
                        if (callback) {
                            callback(content);
                        }
                        return content;
                    } else if (callback) {
                        if (!instance.pendingQueue) instance.pendingQueue = [];
                        instance.pendingQueue.push({action: 'getContent', callback: callback});
                        return '';
                    }
                    return '';
                },
                setContent: function(html) {
                    var instance = window.UEDITOR_INSTANCE;
                    if (!instance) {
                        console.error('UEditor instance not found');
                        return;
                    }
                    if (instance.ready && instance.body) {
                        instance.body.innerHTML = html;
                    } else {
                        if (!instance.pendingQueue) instance.pendingQueue = [];
                        instance.pendingQueue.push({action: 'setContent', value: html});
                    }
                },
                addListener: function(eventName, callback) {
                    if (window.UEDITOR_INSTANCE) {
                        if (!window.UEDITOR_INSTANCE.events[eventName]) {
                            window.UEDITOR_INSTANCE.events[eventName] = [];
                        }
                        window.UEDITOR_INSTANCE.events[eventName].push(callback);
                    }
                },
                removeListener: function(eventName, callback) {
                    if (window.UEDITOR_INSTANCE && window.UEDITOR_INSTANCE.events[eventName]) {
                        var idx = window.UEDITOR_INSTANCE.events[eventName].indexOf(callback);
                        if (idx > -1) {
                            window.UEDITOR_INSTANCE.events[eventName].splice(idx, 1);
                        }
                    }
                },
                fireEvent: function(eventName) {
                    if (window.UEDITOR_INSTANCE && window.UEDITOR_INSTANCE.events[eventName]) {
                        window.UEDITOR_INSTANCE.events[eventName].forEach(function(fn) { fn(); });
                    }
                }
            };
        }
    };
})();